const checkoutStepEl=Array.from(document.getElementsByClassName("checkout-step"));let CheckoutSteps={init:{initNavigation(){checkoutStepEl&&checkoutStepEl.forEach((step=>{step.addEventListener("insStepClick",(async event=>{window.location.href=event.target.dataset.page}))}))}}};setTimeout((()=>{CheckoutSteps.init.initNavigation()}),200);